import React, { useState, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';

function Home() {
  const [clientData, setClientData] = useState(null);
  const navigate = useNavigate(); // नेव्हिगेशनसाठी

  useEffect(() => {
    try {
      const loggedInUser = localStorage.getItem('clientUser');
      if (loggedInUser) {
        setClientData(JSON.parse(loggedInUser));
      }
    } catch (error) {
      console.error("Error parsing user data:", error);
    }
  }, []);

  // कार्डवर क्लिक केल्यावर होणारी ॲक्शन
  const handleCardClick = (target) => {
    if (target === 'payments') {
      alert("आमची पेमेंट सिस्टिम पूर्णपणे सुरक्षित आहे! (Redirecting to help...)");
      // navigate('/help'); // इथे तुझ्या हेल्प पेजचा पाथ टाक
    } else if (target === 'students') {
      navigate('/services'); // व्हेरिफाईड स्टुडंट्स पाहण्यासाठी सर्व्हिसेसवर जा
    } else {
      alert("आम्ही वेळेवर डिलिव्हरीची खात्री देतो!");
    }
  };

  return (
    <div className="home-page" style={{ fontFamily: "'Poppins', sans-serif", overflowX: 'hidden' }}>
      
      {/* 1. Hero Section (तसाच ठेवला आहे) */}
      <header className="hero-section text-white d-flex align-items-center" 
        style={{ 
          background: 'linear-gradient(135deg, #1e3c72 0%, #2a5298 100%)',
          minHeight: '85vh',
          padding: '100px 0'
        }}>
        <div className="container text-center">
          <h1 className="display-2 fw-bold mb-3" style={{ letterSpacing: '-2px', textShadow: '2px 4px 10px rgba(0,0,0,0.2)' }}>
            Web <span style={{ color: '#ffc107' }}>Development</span>
          </h1>
          <p className="lead fs-4 mb-5 opacity-75 mx-auto" style={{ maxWidth: '800px', lineHeight: '1.6' }}>
            Transforming your ideas into digital reality with high-quality, professional student freelancers.
          </p>
          <div className="d-flex justify-content-center gap-3 flex-wrap">
            <Link to="/services" className="btn btn-warning btn-lg px-5 py-3 fw-bold rounded-pill shadow-lg border-0">
              Explore Services
            </Link>
            <Link to="/contact" className="btn btn-outline-light btn-lg px-5 py-3 rounded-pill border-2">
              Contact Us
            </Link> 
          </div>
        </div>
      </header>

      {/* 2. Features Section (Interactive Cards) */}
      <section className="py-5 bg-white">
        <div className="container py-5">
          <div className="text-center mb-5">
            <h2 className="fw-bold display-5 text-dark">Why Choose Us?</h2>
            <div className="mx-auto mt-2" style={{ width: '70px', height: '5px', background: '#ffc107', borderRadius: '10px' }}></div>
            <p className="text-muted mt-3">कार्डवर क्लिक करून अधिक जाणून घ्या!</p>
          </div>
          <div className="row g-4 text-center">
            
            {/* Card 1 */}
            <div className="col-md-4" onClick={() => handleCardClick('payments')} style={{ cursor: 'pointer' }}>
              <div className="card h-100 border-0 shadow-sm p-4 rounded-4 interactive-card">
                <div className="display-4 mb-3">🛡️</div>
                <h4 className="fw-bold text-dark">Secure Payments</h4>
                <p className="text-muted">Your transactions are always safe with our reliable system.</p>
                <small className="text-primary fw-bold">Learn More →</small>
              </div>
            </div>

            {/* Card 2 */}
            <div className="col-md-4" onClick={() => handleCardClick('students')} style={{ cursor: 'pointer' }}>
              <div className="card h-100 border-0 shadow-sm p-4 rounded-4 interactive-card">
                <div className="display-4 mb-3">🎓</div>
                <h4 className="fw-bold text-dark">Verified Students</h4>
                <p className="text-muted">Work with top-tier talent from various professional backgrounds.</p>
                <small className="text-primary fw-bold">View Talent →</small>
              </div>
            </div>

            {/* Card 3 */}
            <div className="col-md-4" onClick={() => handleCardClick('delivery')} style={{ cursor: 'pointer' }}>
              <div className="card h-100 border-0 shadow-sm p-4 rounded-4 interactive-card">
                <div className="display-4 mb-3">⚡</div>
                <h4 className="fw-bold text-dark">Fast Delivery</h4>
                <p className="text-muted">We value your time. Expect quick turnaround for every project.</p>
                <small className="text-primary fw-bold">Our Promise →</small>
              </div>
            </div>

          </div>
        </div>
      </section>

      {/* 3. Map Section (तसाच ठेवला आहे) */}
      <section id="contact" className="py-5" style={{ backgroundColor: '#f8f9fa' }}>
        <div className="container text-center">
          <h2 className="fw-bold mb-4 display-6">📍 Visit Our Hub in <span className="text-primary">Nashik</span></h2>
          <div className="shadow-lg rounded-5 overflow-hidden mx-auto border-white border-5" style={{ maxWidth: '1100px', height: '450px' }}>
            <iframe
              title="Nashik Map"
              src="https://www.google.com"
              width="100%" height="100%" style={{ border: 0 }} allowFullScreen="" loading="lazy"></iframe>
          </div>
        </div>
      </section>

      <style>{`
        .interactive-card { 
          transition: all 0.4s cubic-bezier(0.175, 0.885, 0.32, 1.275); 
          border: 1px solid transparent !important;
        }
        .interactive-card:hover { 
          transform: translateY(-15px) scale(1.03); 
          box-shadow: 0 25px 50px rgba(0,0,0,0.15) !important; 
          border-color: #ffc107 !important;
        }
        .interactive-card:active {
          transform: scale(0.95);
        }
      `}</style>

    </div>
  );
}

export default Home;
